const b = $input.first().json.body || $input.first().json;
const valid_fmt = ['photo','carousel','reel','story','video'];
const fmt = (b.format_type || 'photo').toLowerCase();
if (!valid_fmt.includes(fmt)) {
  return [{ json: { _error: 'invalid format_type, use: ' + valid_fmt.join(',') } }];
}
if (!b.topic && !b.copy_text) {
  return [{ json: { _error: 'topic or copy_text required' } }];
}
return [{ json: {
  brand: b.brand || 'adoff',
  platform: (b.platform || 'twitter').toLowerCase(),
  format_type: fmt,
  topic: b.topic || '',
  copy_text: b.copy_text || '',
  slides: b.slides || (fmt === 'carousel' ? 5 : 1),
  duration_sec: b.duration_sec || (fmt === 'reel' || fmt === 'story' ? 12 : (fmt === 'video' ? 20 : null)),
  requested_by: b.requested_by || 'media-agent'
}}];

const r = $input.first().json;
if (!r || !r.job_id) return [{ json: { status: 'not_found' } }];
return [{ json: {
  job_id: r.job_id,
  brand: r.brand,
  platform: r.platform,
  format_type: r.format_type,
  status: r.status,
  ready: r.status === 'done',
  output_path: r.output_path || null,
  width: r.width, height: r.height,
  file_size: r.file_size,
  gen_seconds: r.gen_seconds,
  error: r.error || null,
  completed_at: r.completed_at
}}];
